/**
 * Deep lesson-level content for every lesson in the HVAC Technician course.
 * Each lesson has: concept explanation, key terms, visual reference,
 * job application, and what to watch for.
 */

export interface LessonContent {
  lessonId: string;
  concept: string;
  keyTerms: { term: string; definition: string }[];
  /** Which diagram ID from the visual library supports this lesson */
  diagramRef?: string;
  /** Real-world job application */
  jobApplication: string;
  /** Common mistakes or things to watch for */
  watchFor: string[];
}

export const HVAC_LESSON_CONTENT: Record<string, LessonContent> = {};

function add(c: LessonContent) { HVAC_LESSON_CONTENT[c.lessonId] = c; }

